resource "cloudflare_api_token" "example_resource" {
  name = "example_resource"

  policy {
    permission_groups = ["<PERMISSION_GROUP_ID>"]
    resources         = { "com.cloudflare.api.account.*" = "*" }
  }

  # Restrict token to specific IP ranges
  condition {
    request_ip {
      in = ["192.0.2.0/24", "198.51.100.0/24"]
    }
  }
}
